namespace IntegraRP.Application.Auth;
public sealed class ResetPasswordUseCase(IAuthenticationRepository repository, IPasswordService passwords, IRefreshTokenService refreshTokens) { public async Task<AuthResult<object>> ExecuteAsync(ResetPasswordRequest request, CancellationToken ct) { if (!passwords.IsValidNewPassword(request.NewPassword, request.ConfirmPassword, out var error)) return AuthResult<object>.Fail(400,"invalid_password_policy",error); var ok = await repository.ConsumePasswordResetAsync(request.TenantSlug.Trim().ToLowerInvariant(), request.Email.Trim().ToLowerInvariant(), refreshTokens.HashToken(request.Token), passwords.Hash(Guid.Empty, request.Email, request.NewPassword), ct); return ok ? AuthResult<object>.Ok(new { reset = true }) : AuthResult<object>.Fail(400,"invalid_reset_token","Token inválido ou expirado."); } }
